import React, { useState, useEffect } from "react";
import axios from "axios";

const StudyRoom = ({ task, onComplete }) => {
    const [seconds, setSeconds] = useState(0);
    const [lastMove, setLastMove] = useState(Date.now());
    const [showQuiz, setShowQuiz] = useState(false);
    const [userAnswer, setUserAnswer] = useState("");
    const [isIdle, setIsIdle] = useState(false);

    useEffect(() => {
        // 1. Mouse Movement Tracker (Anti-Cheat)
        const handleMouseMove = z => {
            setLastMove(Date.now());
            if (isIdle) setIsIdle(false);
        };
        window.addEventListener("mousemove", handleMouseMove);

        // 2. Main Study Timer
        const interval = setInterval(() => {
            setSeconds(prev => {
                // Trigger AI Quiz every 5 minutes (300 seconds)
                if (prev > 0 && prev % 300 === 0) {
                    setShowQuiz(true);
                }
                return prev + 1;
            });

            // Check if user is idle for more than 2 minutes (120000ms)
            if (Date.now() - lastMove > 120000) {
                setIsIdle(true);
            }
        }, 1000);

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            clearInterval(interval);
        };
    }, [lastMove, isIdle]);

    const handleQuizSubmit = () => {
        if (userAnswer.length < 10) {
            alert("Please provide a more detailed answer to continue.");
            return;
        }
        // In a full AI integration, you'd send 'userAnswer' to backend here
        setShowQuiz(false);
        setUserAnswer("");
    };

    return (
        <div className="max-w-2xl mx-auto mt-10 p-8 bg-white shadow-2xl rounded-xl border-t-4 border-blue-600">
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Active Session: {task?.title}</h2>
            <p className="text-gray-500 mb-6">Stay active! AI is monitoring your progress.</p>

            <div className="flex items-center justify-center bg-gray-100 rounded-lg py-10 mb-6">
                <span className="text-5xl font-mono font-bold text-blue-700">
                    {Math.floor(seconds / 60)}:{(seconds % 60).toString().padStart(2, '0')}
                </span>
            </div>

            {isIdle && (
                <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-center animate-pulse">
                    ⚠️ <strong>Idle Detected:</strong> Move your mouse or your Pulse score will drop!
                </div>
            )}

            {/* AI Quiz Modal */}
            {showQuiz && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-white p-6 rounded-lg shadow-2xl max-w-md w-full">
                        <h3 className="text-lg font-bold mb-2">AI Verification Check</h3>
                        <p className="text-gray-600 mb-4 text-sm">To verify you are studying "{task?.title}", explain one key concept you just read.</p>
                        <textarea 
                            className="w-full border-2 border-gray-200 rounded p-2 focus:border-blue-500 outline-none"
                            rows="4"
                            value={userAnswer}
                            onChange={(e) => setUserAnswer(e.target.value)}
                            placeholder="Type your summary here..."
                        />
                        <button 
                            onClick={handleQuizSubmit}
                            className="w-full mt-4 bg-blue-600 text-white font-bold py-2 rounded hover:bg-blue-700 transition"
                        >
                            Verify & Continue
                        </button>
                    </div>
                </div>
            )}

            <button 
                onClick={() => onComplete(task._id)}
                className="w-full bg-green-600 text-white font-bold py-3 rounded-lg hover:bg-green-700 shadow-lg transition"
            >
                Complete Topic & Update AI Schedule
            </button>
        </div>
    );
};

export default StudyRoom;
